import React, { useState, useEffect } from "react";
import { adminService } from "../services/adminService";
import { Check, X, Wallet, Loader2, Image as ImageIcon } from "lucide-react";
import { toast } from "react-hot-toast";
import { usePermissions } from "../hooks/usePermissions";

const WalletWithdraws = () => {
  const { can } = usePermissions();
  const [withdraws, setWithdraws] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchWithdraws();
  }, []);

  const fetchWithdraws = async () => {
    try {
      const data = await adminService.getWalletWithdraws();
      setWithdraws(data || []);
    } catch (error) {
      toast.error(error.message || "Failed to load wallet withdraws");
    } finally {
      setLoading(false);
    }
  };

  const handleApprove = async (id) => {
    if (
      !window.confirm(
        "Approve this withdraw? The amount will be deducted from the user's wallet balance.",
      )
    )
      return;
    try {
      await adminService.approveWalletWithdraw(id);
      toast.success("Withdraw approved successfully!");
      fetchWithdraws();
    } catch (error) {
      toast.error(
        error.response?.data?.message || "Failed to approve withdraw",
      );
    }
  };

  const handleReject = async (id) => {
    const reason = prompt("Enter reason for rejecting this withdraw request:");
    if (reason === null) return; // Cancelled prompt
    try {
      await adminService.rejectWalletWithdraw(id, { rejectionReason: reason });
      toast.success("Withdraw request rejected.");
      fetchWithdraws();
    } catch (error) {
      toast.error(error.response?.data?.message || "Failed to reject withdraw");
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case "approved":
        return "status-delivered";
      case "rejected":
        return "status-cancelled";
      default:
        return "status-pending";
    }
  };

  return (
    <div className="content-area animate-fade-in">
      <div className="section-header">
        <div>
          <h2
            className="page-title"
            style={{ display: "flex", alignItems: "center", gap: "0.75rem" }}
          >
            <div
              className="logo-circle"
              style={{ width: 32, height: 32, boxShadow: "none" }}
            >
              <Wallet size={18} />
            </div>
            Wallet Withdraw Approvals
          </h2>
          <p className="section-subtitle">
            Verify user withdraw requests, view receipt screenshots, and debit
            users' in-app wallets.
          </p>
        </div>
      </div>

      <div className="glass-panel" style={{ padding: 0, overflow: "hidden" }}>
        {loading ? (
          <div className="table-loader">
            <Loader2
              className="animate-spin"
              size={24}
              style={{ margin: "0 auto" }}
            />
            <p style={{ marginTop: "0.5rem" }}>Loading withdraw requests...</p>
          </div>
        ) : (
          <table className="admin-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>User Details</th>
                <th>Withdrawal Account</th>
                <th>Requested Amount</th>
                <th style={{ textAlign: "center" }}>Status</th>
                <th style={{ width: "180px", textAlign: "right" }}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {withdraws.map((w) => (
                <tr key={w._id}>
                  <td>
                    {new Date(w.createdAt).toLocaleString(undefined, {
                      dateStyle: "medium",
                      timeStyle: "short",
                    })}
                  </td>
                  <td>
                    <div style={{ fontWeight: 600, color: "var(--text-main)" }}>
                      {w.user?.name || "N/A"}
                    </div>
                    <div
                      style={{ fontSize: "12px", color: "var(--text-muted)" }}
                    >
                      {w.user?.email || "N/A"}
                    </div>
                    <div
                      style={{
                        fontSize: "11px",
                        color: "var(--text-muted)",
                        textTransform: "capitalize",
                      }}
                    >
                      Role: {w.user?.role || "user"}
                    </div>
                  </td>
                  <td>
                    {w.withdrawalAccountDetails ? (
                      <>
                        <div
                          style={{
                            fontSize: "12px",
                            fontWeight: 600,
                            color: "var(--text-main)",
                          }}
                        >
                          {w.withdrawalAccountDetails.accountTitle}
                        </div>
                        <div
                          style={{
                            fontSize: "12px",
                            color: "var(--text-muted)",
                          }}
                        >
                          {w.withdrawalAccountDetails.accountNumber}
                        </div>
                        <div
                          style={{
                            fontSize: "11px",
                            color: "var(--text-muted)",
                          }}
                        >
                          {w.withdrawalAccountDetails.bankName}
                        </div>
                      </>
                    ) : (
                      <span style={{ color: "var(--text-muted)", fontSize: "12px" }}>
                        No account details
                      </span>
                    )}
                  </td>
                  <td>
                    <strong
                      style={{
                        fontSize: "1.1rem",
                        color: "var(--accent-primary)",
                      }}
                    >
                      Rs {w.amount}
                    </strong>
                  </td>
                  <td style={{ textAlign: "center" }}>
                    <span
                      className={`status-pill ${getStatusColor(w.status)}`}
                      style={{ textTransform: "capitalize" }}
                    >
                      {w.status}
                    </span>
                    {w.status === "rejected" && w.rejectionReason && (
                      <div
                        style={{
                          fontSize: "11px",
                          color: "red",
                          marginTop: "4px",
                          maxWidth: "200px",
                        }}
                      >
                        Reason: {w.rejectionReason}
                      </div>
                    )}
                  </td>
                  <td>
                    {w.status === "pending" ? (
                      <div
                        className="action-btns"
                        style={{ justifyContent: "flex-end", gap: "0.5rem" }}
                      >
                        {can("walletDeposits", "approve") && (
                          <button
                            className="primary-btn"
                            style={{
                              display: "inline-flex",
                              alignItems: "center",
                              justifyContent: "center",
                              gap: "4px",
                              padding: "6px 12px",
                              fontSize: "12px",
                              fontWeight: 600,
                              borderRadius: "6px",
                              border: "none",
                              background: "var(--accent-success)",
                              color: "white",
                              cursor: "pointer",
                            }}
                            title="Approve & Debit Balance"
                            onClick={() => handleApprove(w._id)}
                          >
                            <Check size={14} /> Approve
                          </button>
                        )}
                        {can("walletDeposits", "reject") && (
                          <button
                            className="view-btn"
                            style={{
                              display: "inline-flex",
                              alignItems: "center",
                              justifyContent: "center",
                              gap: "4px",
                              padding: "6px 12px",
                              fontSize: "12px",
                              fontWeight: 600,
                              borderRadius: "6px",
                              border: "1px solid var(--accent-danger)",
                              background: "transparent",
                              color: "var(--accent-danger)",
                              cursor: "pointer",
                            }}
                            title="Reject request"
                            onClick={() => handleReject(w._id)}
                          >
                            <X size={14} /> Reject
                          </button>
                        )}
                      </div>
                    ) : (
                      <div
                        style={{
                          color: "var(--text-muted)",
                          textAlign: "right",
                          fontSize: "13px",
                        }}
                      >
                        Processed
                      </div>
                    )}
                  </td>
                </tr>
              ))}
              {withdraws.length === 0 && (
                <tr>
                  <td colSpan={7} className="empty-table-msg">
                    No withdraw requests found in records.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
};

export default WalletWithdraws;
